mapper.select:
select sv.id, title, type, pic, base_path as basePath, uid,dict.name as languageName,su.username,su.avatar from s_video sv left join dict on sv.type = dict.value and dict.group_type = 'language_type' left join s_user su on su.id = sv.uid
sv.status = 2
and type = #{type}
and title like concat('%',#{title},'%')
and sv.id = #{id}
